// A4: default pricing table resolution, auto from table, exceptions
// queued non-blocking. Currency canonicalization bound to the write
// operation itself -- .toFixed(2) at the exact moment of write, here,
// the one place a price is ever generated.

const fs = require('fs');
const path = require('path');

const prefix = $json.project_prefix;
const docPath = path.join('Working', prefix, 'project_document.json');
const doc = JSON.parse(fs.readFileSync(docPath, 'utf8'));

const FLAT_RATE_FLOOR = 1500.00; // no standalone component prices below this, ever (A15)
const FULL_TIER_MIN = 2500.00;
const ROI_PERCENT = 0.015;

const tierMap = { lowest: null, mid: null, full: null, unresolved_components: [] };

// Lowest -- always free, no gate.
tierMap.lowest = { component: 'compliance_checklist', price: '0.00', gate: 'none' };

// Mid -- component identified from decoded facts against the flat-rate
// table. Anything that doesn't match queues to Manual Lever 1 instead
// of guessing a price.
const allFacts = Object.values(doc.decoded_facts || {}).flat();
const requiresClosout = allFacts.some(f => /closeout|reporting package/i.test(f.fact));
if (requiresClosout) {
  tierMap.mid = { component: 'closeout_reporting_package', price: (2500.00).toFixed(2) };
} else {
  tierMap.mid = { component: 'standard_turnkey_drafting', price: FLAT_RATE_FLOOR.toFixed(2) };
}

// Full -- ROI formula against the funding figure, floor + Manual Lever 1
// if Decode never resolved one clean figure.
if (doc.funding && doc.funding.funding_figure_resolved) {
  const raw = doc.funding.funding_figure.value.replace(/[$,]/g, '');
  const total = parseFloat(raw);
  const roiPrice = Math.max(total * ROI_PERCENT, FULL_TIER_MIN);
  tierMap.full = { component: 'full_proposal_package', price: roiPrice.toFixed(2), basis: 'roi_formula' };
} else {
  tierMap.full = { component: 'full_proposal_package', price: FULL_TIER_MIN.toFixed(2), basis: 'floor_pending_review' };
  tierMap.unresolved_components.push('full_tier_funding_figure');
}

// Deadline Law: expired at intake routes through Manual Lever 1 too.
if (doc.deadline && doc.deadline.expired_at_intake === true) {
  tierMap.unresolved_components.push('solicitation_expired_at_intake');
}

fs.writeFileSync(path.join('Working', prefix, 'tier_map.json'), JSON.stringify(tierMap, null, 2), 'utf8');

return [{ json: { project_prefix: prefix, tier_map: tierMap, requires_manual_lever_1: tierMap.unresolved_components.length > 0 } }];

// Manual Lever 1 exception queue -- blocks pricing/launch for the
// affected scope only. Everything else in the project proceeds; this
// does not halt Build for components that resolved cleanly.

const fs = require('fs');
const path = require('path');
const prefix = $json.project_prefix;
const entry = {
  project_prefix: prefix,
  queued_at: new Date().toISOString(),
  reasons: $json.tier_map.unresolved_components,
  status: 'pending_operator_review'
};
let queue = [];
try { queue = JSON.parse(fs.readFileSync(path.join('Shared', 'manual_lever_1_queue.json'), 'utf8')); } catch (e) {}
queue.push(entry);
fs.writeFileSync(path.join('Shared', 'manual_lever_1_queue.json'), JSON.stringify(queue, null, 2), 'utf8');
return [{ json: { ...($json), queued: true } }];
